"use strict";parserFactory.register("wuxia.blog",()=>new WuxiaBlogParser);class WuxiaBlogParser extends Parser{constructor(){super()}async getChapterUrls(e,t){let r=WuxiaBlogParser.extractPartialChapterList(e),a=WuxiaBlogParser.getUrlsOfTocPages(e);return(await this.getChaptersFromAllTocPages(r,WuxiaBlogParser.extractPartialChapterList,a,t)).reverse()}static extractPartialChapterList(e){let t=e.querySelector("tbody#chapters");return util.hyperlinksToChapterList(t)}static getUrlsOfTocPages(e){let t=[],r=WuxiaBlogParser.getLastPaginationUrl(e);if(null!==r){let e=r.lastIndexOf("/"),a=parseInt(r.substring(e+1)),l=r.substring(0,e+1);for(let e=2;e<=a;++e)t.push(l+e)}return t}static getLastPaginationUrl(e){let t=[...e.querySelectorAll("ul.pagination li a")];return 0===t.length?null:t.pop().href}findContent(e){return e.querySelector("div.article")}extractTitleImpl(e){return e.querySelector("h4.panel-title")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"ul.pager, button, div.recently-nav, div.fb-like"),super.removeUnwantedElementsFromContentElement(e)}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.imageCover")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div[itemprop='description']")]}}